mapper.select:
SELECT GETBUYERDEPTNAME(CVUR.GATE_CD, CVUR.COMPANY_CD , CVUR.DEPT_CD, 'KO') AS DEPT_NM , CUT.USER_ID , GETUSERNAME(CVUR.GATE_CD, CUT.USER_ID, 'KO') AS USER_NM , CASE WHEN IS_CORPORATION = 'true' THEN '법인' ELSE '개인' END AS IS_CORPORATION , TO_CHAR ( TO_DATE ( SUBSTR( BEFORE_DATE, 0 , 8 ) , 'YYYYMMDD' ) , 'YYYY-MM-DD') AS BEFORE_DATE , TO_CHAR ( TO_DATE ( SUBSTR( AFTER_DATE, 0 , 8 ) , 'YYYYMMDD' ) , 'YYYY-MM-DD') AS AFTER_DATE , CASE WHEN CERT_STATUS = 'Revocation' THEN '만료' ELSE '유효' END AS CERT_STATUS FROM CERT_USER_TABLE CUT JOIN STOCCUST CUST ON CUT.IRS_NUM = CUST.IRS_NUM JOIN STOCCVUR CVUR ON CUT.USER_ID = CVUR.USER_ID WHERE CVUR.GATE_CD = #{ses.gateCd} AND CVUR.COMPANY_CD = #{ses.companyCd}
AND ( SUBSTR( CUT.BEFORE_DATE, 0, 8 ) ) >= (#{BEFORE_DATE_FROM})
AND ( SUBSTR( CUT.BEFORE_DATE, 0, 8 ) ) <= (#{BEFORE_DATE_TO})
AND CUT.CERT_STATUS = #{CERT_STATUS}
AND UPPER(CUT.USER_ID) LIKE '%' UPPER(#{USER_ID}) '%'
ORDER BY CERT_SEQ DESC
